function CustomShopSwordLight:onEquipGoods(player, goods)
    local setting = self.Settings[goods.SettingId]
    if not setting then
        return
    end
    player.info:setValue("attack_skill_name", setting.SceneAction)
end

function CustomShopSwordLight:onUnloadGoods(player, goods)
    local setting = self.Settings[goods.SettingId]
    if not setting then
        return
    end
    player.info:setValue("attack_skill_name", "attack2")
end